import { db } from './mockDb';
import { User } from '../lib/types';

const genToken = () => Math.random().toString(36).substring(2);

export const authService = {
  login(email: string, password: string): Promise<User> {
    // password ignorado (mock)
    const existing = db.users.find(u => u.email === email);
    if (!existing) return Promise.reject(new Error('Usuario no encontrado'));
    return Promise.resolve(existing);
  },
  register(name: string, email: string, password: string): Promise<User> {
    const exists = db.users.some(u => u.email === email);
    if (exists) return Promise.reject(new Error('Email en uso'));
    const newUser: User = { id: Date.now().toString(), name, email, token: genToken() };
    db.users.push(newUser);
    return Promise.resolve(newUser);
  }
};

