import { db } from './mockDb';
import { Reservation } from '../lib/types';

export const reservationService = {
  listByUser(userId: string): Promise<Reservation[]> {
    return Promise.resolve(db.reservations.filter(r => r.userId === userId));
  },
  create(roomId: string, userId: string): Promise<Reservation> {
    const now = new Date().toISOString();
    const res: Reservation = { id: Date.now().toString(), roomId, userId, from: now, to: now };
    db.reservations.push(res);
    return Promise.resolve(res);
  }
};

import { createContext, useState, ReactNode } from 'react';
