import { createContext, useEffect, useState, ReactNode } from 'react';
import { Reservation } from '../lib/types';
import { reservationService } from '../services/reservationService';
import { useAuth } from '../hooks/useAuth';

interface ReservationCtx {
  reservations: Reservation[];
  add: (r: Reservation) => void;
}

export const ReservationContext = createContext<ReservationCtx>({} as ReservationCtx);

export const ReservationProvider = ({ children }: { children: ReactNode }) => {
  const { user } = useAuth();
  const [reservations, setReservations] = useState<Reservation[]>([]);

  useEffect(() => {
    if (!user) return;
    reservationService.listByUser(user.id).then(setReservations);
  }, [user]);

  const add = (r: Reservation) => setReservations(prev => [...prev, r]);

  return (
    <ReservationContext.Provider value={{ reservations, add }}>
      {children}
    </ReservationContext.Provider>
  );
};

