import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { MainLayout } from '../components/layout/MainLayout';
import { Room } from '../lib/types';
import { roomService } from '../services/roomService';
import { Button } from '../components/ui/Button';
import { useAuth } from '../hooks/useAuth';
import { reservationService } from '../services/reservationService';
import { useReservations } from '../hooks/useReservations';

export default function RoomDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { add } = useReservations();
  const [room, setRoom] = useState<Room | undefined>();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    roomService.byId(id!).then(r => {
      setRoom(r);
      setLoading(false);
    });
  }, [id]);

  const handleReserve = async () => {
    if (!user) return navigate('/login');
    const reservation = await reservationService.create(id!, user.id);
    add(reservation);
    navigate('/reservations');
  };

  if (loading) return <MainLayout>Cargando...</MainLayout>;
  if (!room) return <MainLayout>Habitación no encontrada</MainLayout>;

  return (
    <MainLayout>
      <img src={room.image} alt={room.title} className="w-full h-60 object-cover rounded mb-4" />
      <h1 className="text-2xl font-bold mb-2">{room.title}</h1>
      <p className="mb-4">{room.description}</p>
      <p className="font-semibold mb-6">${room.price} / noche</p>
      <Button onClick={handleReserve}>Reservar</Button>
    </MainLayout>
  );
}

import { MainLayout } from '../components/layout/MainLayout';
import { useReservations } from '../hooks/useReservations';
import { useRooms } from '../hooks/useRooms';
import { ReservationCard } from '../components/shared/ReservationCard';

export default function MyReservations() {
  const { reservations } = useReservations();
  const { rooms } = useRooms();

  const getRoom = (id: string) => rooms.find(r => r.id === id)!;

  return (
    <MainLayout>
      <h1 className="text-2xl font-bold mb-4">Mis reservas</h1>
      {reservations.length === 0 ? (
        <p>No tienes reservas.</p>
      ) : (
        <div className="space-y-4">
          {reservations.map(res => (
            <ReservationCard key={res.id} reservation={res} room={getRoom(res.roomId)} />
          ))}
        </div>
      )}
    </MainLayout>
  );
}

import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import RoomDetail from './pages/RoomDetail';
import MyReservations from './pages/MyReservations';
import { AuthProvider } from './contexts/AuthContext';
import { RoomProvider } from './contexts/RoomContext';
import { ReservationProvider } from './contexts/ReservationContext';
import { ProtectedRoute } from './components/shared/ProtectedRoute';

export default function App() {
  return (
    <AuthProvider>
      <RoomProvider>
        <ReservationProvider>
          <BrowserRouter>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              <Route path="/rooms/:id" element={<RoomDetail />} />
              <Route element={<ProtectedRoute />}>
                <Route path="/reservations" element={<MyReservations />} />
              </Route>
            </Routes>
          </BrowserRouter>
        </ReservationProvider>
      </RoomProvider>
    </AuthProvider>
  );
